// Generates original, branded SVG product/category visuals into public/products
// and public/categories. These are 100% generated by us — no third-party imagery —
// so the storefront looks complete without any licensing concerns. Re-run with:
//   node scripts/generate-product-images.mjs
import { mkdirSync, writeFileSync } from "node:fs"
import { dirname, resolve } from "node:path"
import { fileURLToPath } from "node:url"

const __dirname = dirname(fileURLToPath(import.meta.url))
const publicDir = resolve(__dirname, "../public")

const THEMES = {
  workstation: {
    from: "#0B1220",
    to: "#1E3A8A",
    accent: "#60A5FA",
    label: "AI WORKSTATION",
  },
  server: {
    from: "#0B0F1A",
    to: "#0F766E",
    accent: "#2DD4BF",
    label: "GPU RACK SERVER",
  },
  cpu: {
    from: "#1A0B20",
    to: "#6D28D9",
    accent: "#A78BFA",
    label: "CPU-PLATFORM WORKSTATION",
  },
  component: {
    from: "#1A1206",
    to: "#92400E",
    accent: "#FBBF24",
    label: "COMPONENT",
  },
}

// Stylized hardware silhouettes (abstract, original) drawn per product type.
function glyph(type, accent) {
  switch (type) {
    case "workstation":
      return `
        <rect x="330" y="200" width="140" height="220" rx="10" fill="#0F172A" stroke="${accent}" stroke-width="3"/>
        <rect x="350" y="225" width="100" height="26" rx="4" fill="${accent}" opacity="0.85"/>
        <rect x="350" y="262" width="100" height="14" rx="3" fill="${accent}" opacity="0.35"/>
        <rect x="350" y="284" width="100" height="14" rx="3" fill="${accent}" opacity="0.35"/>
        <circle cx="360" cy="390" r="7" fill="${accent}"/>
        <rect x="378" y="384" width="60" height="12" rx="3" fill="${accent}" opacity="0.5"/>`
    case "server":
      return `
        <rect x="250" y="240" width="300" height="46" rx="6" fill="#0F172A" stroke="${accent}" stroke-width="2.5"/>
        <rect x="250" y="296" width="300" height="46" rx="6" fill="#0F172A" stroke="${accent}" stroke-width="2.5"/>
        ${[0, 1]
          .map((row) =>
            [0, 1, 2, 3, 4, 5, 6, 7]
              .map(
                (i) =>
                  `<rect x="${266 + i * 34}" y="${
                    254 + row * 56
                  }" width="20" height="18" rx="3" fill="${accent}" opacity="${
                    0.55 + (i % 3) * 0.15
                  }"/>`
              )
              .join("")
          )
          .join("")}
        <circle cx="528" cy="263" r="5" fill="${accent}"/>
        <circle cx="528" cy="319" r="5" fill="${accent}"/>`
    case "cpu":
      return `
        <rect x="320" y="230" width="160" height="160" rx="14" fill="#0F172A" stroke="${accent}" stroke-width="3"/>
        <rect x="352" y="262" width="96" height="96" rx="8" fill="${accent}" opacity="0.8"/>
        <text x="400" y="318" text-anchor="middle" font-family="Inter, sans-serif" font-size="26" font-weight="700" fill="#0B1220">VC</text>
        ${[0, 1, 2, 3, 4, 5]
          .map(
            (i) =>
              `<rect x="${
                336 + i * 22
              }" y="210" width="8" height="20" rx="2" fill="${accent}"/><rect x="${
                336 + i * 22
              }" y="390" width="8" height="20" rx="2" fill="${accent}"/>`
          )
          .join("")}
        ${[0, 1, 2, 3, 4, 5]
          .map(
            (i) =>
              `<rect x="300" y="${
                252 + i * 22
              }" width="20" height="8" rx="2" fill="${accent}"/><rect x="480" y="${
                252 + i * 22
              }" width="20" height="8" rx="2" fill="${accent}"/>`
          )
          .join("")}`
    default: // component
      return `
        <circle cx="400" cy="310" r="78" fill="none" stroke="${accent}" stroke-width="4"/>
        <circle cx="400" cy="310" r="30" fill="${accent}" opacity="0.85"/>
        ${[0, 45, 90, 135, 180, 225, 270, 315]
          .map((a) => {
            const r = (a * Math.PI) / 180
            const x1 = 400 + Math.cos(r) * 78
            const y1 = 310 + Math.sin(r) * 78
            const x2 = 400 + Math.cos(r) * 100
            const y2 = 310 + Math.sin(r) * 100
            return `<line x1="${x1.toFixed(1)}" y1="${y1.toFixed(
              1
            )}" x2="${x2.toFixed(1)}" y2="${y2.toFixed(
              1
            )}" stroke="${accent}" stroke-width="6" stroke-linecap="round"/>`
          })
          .join("")}`
  }
}

function svg({ title, subtitle, type, w = 800, h = 600 }) {
  const t = THEMES[type]
  const id = Math.random().toString(36).slice(2, 8)
  const titleLines = wrap(title, 22)
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${w}" height="${h}" viewBox="0 0 800 600" role="img" aria-label="${escapeXml(
    title
  )}">
  <defs>
    <linearGradient id="bg${id}" x1="0" y1="0" x2="1" y2="1">
      <stop offset="0" stop-color="${t.from}"/>
      <stop offset="1" stop-color="${t.to}"/>
    </linearGradient>
    <radialGradient id="glow${id}" cx="0.5" cy="0.45" r="0.6">
      <stop offset="0" stop-color="${t.accent}" stop-opacity="0.25"/>
      <stop offset="1" stop-color="${t.accent}" stop-opacity="0"/>
    </radialGradient>
    <pattern id="dots${id}" width="26" height="26" patternUnits="userSpaceOnUse">
      <circle cx="2" cy="2" r="1.4" fill="#FFFFFF" opacity="0.05"/>
    </pattern>
  </defs>
  <rect width="800" height="600" fill="url(#bg${id})"/>
  <rect width="800" height="600" fill="url(#dots${id})"/>
  <rect width="800" height="600" fill="url(#glow${id})"/>
  ${glyph(type, t.accent)}
  <text x="56" y="92" font-family="Inter, system-ui, sans-serif" font-size="15" letter-spacing="3" font-weight="600" fill="${
    t.accent
  }">${t.label}</text>
  ${titleLines
    .map(
      (line, i) =>
        `<text x="56" y="${
          480 + i * 40
        }" font-family="Inter, system-ui, sans-serif" font-size="34" font-weight="700" fill="#FFFFFF">${escapeXml(
          line
        )}</text>`
    )
    .join("\n  ")}
  <text x="56" y="${
    492 + titleLines.length * 40
  }" font-family="Inter, system-ui, sans-serif" font-size="17" fill="#CBD5E1">${escapeXml(
    subtitle
  )}</text>
  <text x="744" y="92" text-anchor="end" font-family="Inter, system-ui, sans-serif" font-size="16" font-weight="700" fill="#FFFFFF" opacity="0.9">VectraCompute</text>
</svg>`
}

function wrap(text, max) {
  const words = text.split(" ")
  const lines = []
  let cur = ""
  for (const w of words) {
    if ((cur + " " + w).trim().length > max) {
      lines.push(cur.trim())
      cur = w
    } else cur += " " + w
  }
  if (cur.trim()) lines.push(cur.trim())
  return lines.slice(0, 2)
}

function escapeXml(s) {
  return s.replace(
    /[<>&'"]/g,
    (c) =>
      ({ "<": "&lt;", ">": "&gt;", "&": "&amp;", "'": "&apos;", '"': "&quot;" }[
        c
      ])
  )
}

