mkdirSync(resolve(publicDir, "products"), { recursive: true })
mkdirSync(resolve(publicDir, "categories"), { recursive: true })

for (const [handle, title, subtitle, type] of PRODUCTS) {
  writeFileSync(
    resolve(publicDir, "products", `${handle}.svg`),
    svg({ title, subtitle, type })
  )
}
for (const [handle, title, subtitle, type] of CATEGORIES) {
  writeFileSync(
    resolve(publicDir, "categories", `${handle}.svg`),
    svg({ title, subtitle, type, w: 1200, h: 630 })
  )
}

// Generic placeholders so products/categories added later in Medusa Admin (without an
// uploaded image) still render a branded visual instead of a broken image.
writeFileSync(
  resolve(publicDir, "products", "_placeholder.svg"),
  svg({
    title: "VectraCompute",
    subtitle: "Built to order",
    type: "workstation",
  })
)
writeFileSync(
  resolve(publicDir, "categories", "_placeholder.svg"),
  svg({
    title: "VectraCompute",
    subtitle: "Browse the catalog",
    type: "workstation",
    w: 1200,
    h: 630,
  })
)

// Manifest of handles we generated art for, consumed by the storefront fallback logic.
const manifestDir = resolve(__dirname, "../src/lib/data")
mkdirSync(manifestDir, { recursive: true })
writeFileSync(
  resolve(manifestDir, "generated-image-handles.json"),
  JSON.stringify(
    {
      products: PRODUCTS.map(([handle]) => handle),
      categories: CATEGORIES.map(([handle]) => handle),
    },
    null,
    2
  ) + "\n"
)

console.log(
  `Generated ${PRODUCTS.length} product images, ${CATEGORIES.length} category images, placeholders, and manifest.`
)
